pure fn factorial(n: Number) -> Number {
    if n <= 1 { return 1 }
    return n * factorial(n - 1)
}

entry main(x: Text) { return factorial(7) }

pure fn reverse_string(s: Text) -> Text {
    return join(reverse(split(s, "")), "")
}

entry main(x: Text) { return reverse_string("hello world") }

pure fn is_vowel(c: Text) -> Boolean {
    return c in ["a", "e", "i", "o", "u"]
}

pure fn count_vowels(s: Text) -> Number {
    total = 0
    for c in split(lower(s), "") {
        if is_vowel(c) { total = total + 1 }
    }
    return total
}

entry main(x: Text) { return count_vowels("Programming is fun") }

pure fn find_largest(numbers: List[Number]) -> Number {
    max_num = numbers[0]
    for num in numbers {
        if num > max_num { max_num = num }
    }
    return max_num
}

entry main(x: Text) {
    numbers = [34, 12, 89, 3, 56, 72]
    return find_largest(numbers)
}

pure fn sort_words(words: Text) -> Text {
    word_list = split(words, " ")
    sorted_list = sort(word_list)
    return join(sorted_list, " ")
}

entry main(x: Text) {
    return sort_words("banana cherry apple date")
}

pure fn is_even(n: Number) -> Boolean {
    return n % 2 == 0
}

pure fn sum_of_evens(limit: Number) -> Number {
    total = 0
    for i in range(1, limit + 1) {
        if is_even(i) { total = total + i }
    }
    return total
}

entry main(x: Text) {
    return sum_of_evens(100)
}

pure fn fahrenheit_to_celsius(f: Number) -> Number {
    return (f - 32) * 5 / 9
}

entry main(x: Text) {
    temp_f = 98.6
    temp_c = fahrenheit_to_celsius(temp_f)
    return join(["Temperature in Celsius: ", to_text(temp_c)], "")
}

pure fn is_long_word(word: Text) -> Boolean {
    return length(word) > 3
}

pure fn count_long_words(sentence: Text) -> Number {
    total = 0
    for word in split(sentence, " ") {
        if is_long_word(word) { total = total + 1 }
    }
    return total
}

entry main(x: Text) {
    sentence = "the quick brown fox jumps over the lazy dog"
    return count_long_words(sentence)
}

pure fn is_palindrome(s: Text) -> Boolean {
    cleaned = lower(trim(s))
    reversed = reverse(cleaned)
    return cleaned == reversed
}

entry main(x: Text) { return is_palindrome("racecar") }

pure fn calculate_average(numbers: List[Number]) -> Number {
    total = 0
    for num in numbers {
        total = total + num
    }
    return total / length(numbers)
}

entry main(x: Text) {
    numbers = [85, 92, 78, 95, 88]
    return calculate_average(numbers)
}

pure fn remove_duplicates(list: List[Number]) -> List[Number] {
    unique_list = []
    for item in list {
        if not contains(unique_list, item) {
            unique_list = append(unique_list, item)
        }
    }
    return unique_list
}

entry main(x: Text) {
    input_list = [1, 3, 2, 3, 1, 4, 2, 5]
    return remove_duplicates(input_list)
}

pure fn count_frequency(s: Text) -> Text {
    freq = {}
    for c in split(s, "") {
        if has_key(freq, c) {
            freq[c] = freq[c] + 1
        } else {
            freq[c] = 1
        }
    }
    result = []
    for key, value in items(freq) {
        result = append(result, join([key, ": ", to_text(value)], ""))
    }
    return join(result, ", ")
}

entry main(x: Text) { return count_frequency("mississippi") }

pure fn fibonacci(n: Number) -> Number {
    if n <= 1 { return n }
    return fibonacci(n - 1) + fibonacci(n - 2)
}

entry main(x: Text) {
    results = []
    for i in range(0, 10) {
        results = append(results, to_text(fibonacci(i)))
    }
    return join(results, ", ")
}

pure fn is_divisible_by_4(n: Number) -> Boolean {
    return n % 4 == 0
}

entry main(numbers: Text) {
