pure fn mean(numbers: List[Number]) -> Number {
    total = 0
    for num in numbers {
        total = total + num
    }
    return total / length(numbers)
}

pure fn variance(numbers: List[Number], m: Number) -> Number {
    total = 0
    for num in numbers {
        diff = num - m
        total = total + (diff * diff)
    }
    return total / length(numbers)
}

pure fn standard_deviation(numbers: List[Number]) -> Number {
    m = mean(numbers)
    v = variance(numbers, m)
    return sqrt(v)
}

entry main(x: Text) {
    data = [10, 12, 23, 23, 16, 23, 21, 16]
    sd = standard_deviation(data)
    explanation = if sd > mean(data) { "highly variable" } else { "not highly variable" }
    return join(["Standard Deviation: ", to_text(sd), ", Data is ", explanation], "")
}

pure fn reverse_word(word: Text) -> Text {
    return join(reverse(split(word, "")), "")
}

pure fn reverse_words_in_sentence(sentence: Text) -> Text {
    words = split(sentence, " ")
    reversed_words = []
    for word in words {
        reversed_words = append(reversed_words, reverse_word(word))
    }
    return join(reversed_words, " ")
}

entry main(x: Text) {
    sentence = "hello world foo"
    reversed_sentence = reverse_words_in_sentence(sentence)
    creative_sentence = join(["The reversed words are:", reversed_sentence], " ")
